  "inlineSchema": "// Este es tu esquema de Prisma, define las tablas de la base de datos.\n// Documentación: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ==========================================\n// ENUMS (Listas de valores permitidos)\n// ==========================================\n\nenum EstadoAsistencia {\n  PRESENTE\n  AUSENTE\n  JUSTIFICADO\n}\n\nenum RolUsuario {\n  ADMINISTRADOR\n  PROFESOR\n  PADRE\n}\n\n// ==========================================\n// MODELOS / TABLAS\n// ==========================================\n\nmodel Usuario {\n  id       Int        @id @default(autoincrement())\n  nombre   String\n  apellido String\n  email    String?    @unique\n  password String? // Se añadirá seguridad luego, es opcional por ahora\n  rol      RolUsuario @default(PADRE)\n  dni      String?    @unique // Útil para login rápido de padres\n\n  // Un profesor puede tener varios clubes a su cargo\n  clubes Club[] @relation(\"ProfesorClub\")\n\n  // Relación con Alumno (un padre tiene varios hijos)\n  hijos Alumno[] @relation(\"PadreAlumno\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Club {\n  id          Int     @id @default(autoincrement())\n  nombre      String\n  descripcion String?\n\n  // Relación: Todo club tiene un profesor a cargo\n  profesorId Int\n  profesor   Usuario @relation(\"ProfesorClub\", fields: [profesorId], references: [id])\n\n  inscripciones Inscripcion[]\n  sesiones      Sesion[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Alumno {\n  id       Int    @id @default(autoincrement())\n  nombre   String\n  apellido String\n  grado    String // Ej: \"1ro Secundaria\"\n\n  // Relación: Un alumno tiene un padre responsable en el sistema\n  padreId Int?\n  padre   Usuario? @relation(\"PadreAlumno\", fields: [padreId], references: [id])\n\n  inscripciones Inscripcion[]\n  asistencias   Asistencia[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// Tabla intermedia: Qué alumno está en qué club\nmodel Inscripcion {\n  id Int @id @default(autoincrement())\n\n  alumnoId Int\n  alumno   Alumno @relation(fields: [alumnoId], references: [id])\n\n  clubId Int\n  club   Club @relation(fields: [clubId], references: [id])\n\n  fechaInscripcion DateTime @default(now())\n\n  // Validacion: Un alumno no puede estar inscrito 2 veces en el mismo club exacto\n  @@unique([alumnoId, clubId])\n}\n\n// Cada vez que un profesor \"Abre lista\" se crea una Sesion\nmodel Sesion {\n  id    Int      @id @default(autoincrement())\n  fecha DateTime @default(now())\n  tema  String? // Ej: \"Práctica de tiros libres\"\n\n  clubId Int\n  club   Club @relation(fields: [clubId], references: [id])\n\n  asistencias Asistencia[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// El registro exacto de si vino o no vino\nmodel Asistencia {\n  id     Int              @id @default(autoincrement())\n  estado EstadoAsistencia\n\n  sesionId Int\n  sesion   Sesion @relation(fields: [sesionId], references: [id])\n\n  alumnoId Int\n  alumno   Alumno @relation(fields: [alumnoId], references: [id])\n\n  observacion String? // Ej: \"Llegó tarde 15 min\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Validacion: Un alumno solo debe tener un registro de asistencia por sesión\n  @@unique([sesionId, alumnoId])\n}\n",
